patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 28d7e1ce401e..a4039243c409 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -3019,6 +3019,9 @@ static bool isKnownNonZeroFromOperator(const Operator *I,
     // (X | (X != 0)) is non zero
     if (matchOpWithOpEqZero(I->getOperand(0), I->getOperand(1)))
       return true;
+    // X != Y implies X | Y != 0.
+    if (::isKnownNonEqual(I->getOperand(0), I->getOperand(1), DemandedElts, Depth, Q))
+      return true;
     // X | Y != 0 if X != 0 or Y != 0.
     return isKnownNonZero(I->getOperand(1), DemandedElts, Q, Depth) ||
            isKnownNonZero(I->getOperand(0), DemandedElts, Q, Depth);
@@ -3527,9 +3530,8 @@ getInvertibleOperands(const Operator *Op1,
     if (!cast<PossiblyDisjointInst>(Op1)->isDisjoint() ||
         !cast<PossiblyDisjointInst>(Op2)->isDisjoint())
       break;
-    [[fallthrough]];
   case Instruction::Xor:
-  case Instruction::Add: {
+  case Instruction::Xor:
     Value *Other;
     if (match(Op2, m_c_BinOp(m_Specific(Op1->getOperand(0)), m_Value(Other))))
       return std::make_pair(Op1->getOperand(1), Other);
@@ -3537,8 +3539,6 @@ getInvertibleOperands(const Operator *Op1,
       return std::make_pair(Op1->getOperand(0), Other);
     break;
   }
-  case Instruction::Sub:
-    if (Op1->getOperand(0) == Op2->getOperand(0))
       return getOperands(1);
     if (Op1->getOperand(1) == Op2->getOperand(1))
       return getOperands(0);
@@ -3842,6 +3842,11 @@ static bool isKnownNonEqual(const Value *V1, const Value *V2,
     }
   }

+  // X | Y != 0 iff X != 0 or Y != 0.
+  // We can't directly check X != 0 or Y != 0 from here unless V2 is 0.
+  // This logic is mostly handled in isKnownNonZero.
+
+
   if (isNonEqualSelect(V1, V2, DemandedElts, Depth, Q) ||
       isNonEqualSelect(V2, V1, DemandedElts, Depth, Q))
     return true;

